import React, { useEffect, useMemo, useRef, useState } from 'react';
import { taskService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/worker/worker-tasks.css';
import { pushToast } from "../../utils/toastBridge";
const STATUS_META = {
  PENDING: {
    label: 'â³ Chá» lÃ m',
    color: '#92400e',
    bg: '#fef3c7'
  },
  IN_PROGRESS: {
    label: 'ðŸ”„ Äang lÃ m',
    color: '#0c4a6e',
    bg: '#dbeafe'
  },
  COMPLETED: {
    label: 'âœ… HoÃ n thÃ nh',
    color: '#166534',
    bg: '#dcfce7'
  }
};
const STATUS_FLOW = {
  PENDING: 'IN_PROGRESS',
  IN_PROGRESS: 'COMPLETED',
  COMPLETED: null
};
const SORT_OPTIONS = {
  OVERDUE_PRIORITY: 'OVERDUE_PRIORITY',
  NEAREST_DUE: 'NEAREST_DUE'
};
const formatDate = value => {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '-';
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const formatDateTime = value => {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '-';
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const fileToDataUrl = file => new Promise((resolve, reject) => {
  const reader = new FileReader();
  reader.onload = () => resolve(reader.result);
  reader.onerror = () => reject(new Error('KhÃ´ng Ä‘á»c Ä‘Æ°á»£c file áº£nh'));
  reader.readAsDataURL(file);
});
const getDateStart = value => {
  if (!value) return null;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  return new Date(date.getFullYear(), date.getMonth(), date.getDate());
};
const getDuePriority = value => {
  const dueDate = getDateStart(value);
  if (!dueDate) return 3;
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  if (dueDate < today) return 0;
  if (dueDate.getTime() === today.getTime()) return 1;
  return 2;
};
const getDueLabel = value => {
  const dueDate = getDateStart(value);
  if (!dueDate) return {
    text: 'KhÃ´ng cÃ³ háº¡n',
    color: '#6b7280',
    bg: '#f3f4f6'
  };
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  if (dueDate < today) return {
    text: 'QuÃ¡ háº¡n',
    color: '#991b1b',
    bg: '#fee2e2'
  };
  if (dueDate.getTime() === today.getTime()) return {
    text: 'Äáº¿n háº¡n hÃ´m nay',
    color: '#92400e',
    bg: '#fef3c7'
  };
  return {
    text: 'ChÆ°a Ä‘áº¿n háº¡n',
    color: '#1f2937',
    bg: '#e5e7eb'
  };
};
const getStatusChip = status => {
  const normalizedStatus = String(status || 'PENDING').toUpperCase();
  const meta = STATUS_META[normalizedStatus] || STATUS_META.PENDING;
  return <span className="status-chip" style={{
    '--status-bg': meta.bg,
    '--status-color': meta.color
  }}>
      {meta.label}
    </span>;
};
const WorkerTasks = () => {
  const [loading, setLoading] = useState(true);
  const [tasks, setTasks] = useState([]);
  const error = null;
  const success = null;
  const [statusFilter, setStatusFilter] = useState('ALL');
  const [sortBy, setSortBy] = useState(SORT_OPTIONS.OVERDUE_PRIORITY);
  const [updatingTaskId, setUpdatingTaskId] = useState('');

  // Tráº¡ng thÃ¡i modal
  const [modalOpen, setModalOpen] = useState(false);
  const [selectedTask, setSelectedTask] = useState(null);
  const [selectedImageFile, setSelectedImageFile] = useState(null);
  const [selectedTaskImages, setSelectedTaskImages] = useState([]);
  const [loadingImages, setLoadingImages] = useState(false);
  const [uploadingImage, setUploadingImage] = useState(false);
  const imageInputRef = useRef(null);
  const fetchTasks = async () => {
    try {
      setLoading(true);
      const response = await taskService.getAllTasks();
      const taskList = response?.data?.data || [];
      setTasks(taskList);
    } catch (loadError) {
      setTasks([]);
      setSelectedTaskImages([]);
      pushToast({
        title: "Thất bại",
        message: loadError?.response?.data?.message || 'KhÃ´ng táº£i Ä‘Æ°á»£c danh sÃ¡ch cÃ´ng viá»‡c',
        type: "error"
      });
    } finally {
      setLoading(false);
    }
  };
  useEffect(() => {
    fetchTasks();
  }, []);
  const loadTaskImages = async taskId => {
    if (!taskId) {
      setSelectedTaskImages([]);
      return;
    }
    try {
      setLoadingImages(true);
      const response = await taskService.getTaskById(taskId);
      setSelectedTaskImages(response?.data?.data?.images || []);
    } catch (loadError) {
      setSelectedTaskImages([]);
      pushToast({
        title: "Thất bại",
        message: loadError?.response?.data?.message || 'KhÃ´ng táº£i Ä‘Æ°á»£c áº£nh minh chá»©ng cá»§a cÃ´ng viá»‡c',
        type: "error"
      });
    } finally {
      setLoadingImages(false);
    }
  };
  const openModal = async task => {
    setSelectedTask(task);
    setModalOpen(true);
    setSelectedImageFile(null);
    if (imageInputRef.current) imageInputRef.current.value = '';
    await loadTaskImages(task.task_id);
  };
  const closeModal = () => {
    setModalOpen(false);
    setSelectedTask(null);
    setSelectedImageFile(null);
    setSelectedTaskImages([]);
    if (imageInputRef.current) imageInputRef.current.value = '';
  };
  const handleImageChange = event => {
    const file = event.target.files?.[0] || null;
    if (!file) {
      setSelectedImageFile(null);
      return;
    }
